namespace sv_f673086dd3a348b99ff0f9c376186555.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "profile";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

.settings-sidebar {
    min-width: 220px;
    background: var(--bs-light, #f8f9fa);
    border-right: 1px solid var(--bs-border-color, #dee2e6);
    padding: 1rem 0;
    height: 100%;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: var(--bs-body-color, #212529);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.nav-link:hover {
    background: rgba(0, 0, 0, 0.04);
}

.nav-link.active {
    background: rgba(13, 110, 253, 0.08);
    color: var(--bs-primary, #0d6efd);
    border-left-color: var(--bs-primary, #0d6efd);
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@* Expandable panel for changing password *@

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button"
         @onclick="ToggleExpanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_errorMessage))
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (_success)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="HandleSubmit" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private bool _saving;
    private bool _success;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task HandleSubmit()
    {
        _errorMessage = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _errorMessage = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _errorMessage = "New password must be at least 8 characters.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _success = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_f673086dd3a348b99ff0f9c376186555.Services

@* Sessions table with revoke confirmation *@

<div class="card">
    <div class="card-header">
        <h6 class="mb-0">Active Sessions</h6>
    </div>
    <div class="card-body p-0">
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th class="text-end">Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td class="text-end">
                                @if (session.Id == CurrentSessionId)
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@* Revoke confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong>
                        from <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                    <p class="text-muted small mb-0">This will sign the user out of that device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalHours < 1) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalDays < 1) return $"{(int)diff.TotalHours}h ago";
        return lastActive.ToString("MMM d, yyyy");
    }
}

