<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <p class="text-muted small mb-0">
                    Add an extra layer of security to your account.
                </p>
            </div>
            <div class="d-flex align-items-center gap-2">
                <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox"
                           checked="@Settings.TwoFactorEnabled"
                           @onchange="HandleToggle2FA" />
                </div>
            </div>
        </div>
    </div>

    @if (Settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Settings.Sessions"
                         CurrentSessionId="@Settings.Sessions.FirstOrDefault()?.Id"
                         OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings Settings { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<bool> OnToggle2FA { get; set; }

    private async Task HandleToggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }
}

