{"file_text": "@using sv_f673086dd3a348b99ff0f9c376186555.Services

<div class="settings-section">
    <h4 class="mb-4">Appearance</h4>

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme.Key}")"
                               checked="@(_theme == theme.Key)"
                               @onchange="() => _theme = theme.Key" />
                        <label class="form-check-label" for="@($"theme-{theme.Key}")">@theme.Label</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size.Key}")"
                               checked="@(_fontSize == size.Key)"
                               @onchange="() => _fontSize = size.Key" />
                        <label class="form-check-label" for="@($"fs-{size.Key}")">@size.Label</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang.Key">@lang.Label</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p>This is how your content will look with the selected settings.</p>
                    <button class="btn btn-sm btn-primary">Sample Button</button>
                    <span class="badge bg-info ms-2">Badge</span>
                </div>
                <div class="preview-footer text-muted">
                    Footer area · @GetLanguageLabel()
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings Settings { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "system";
    private string _fontSize = "medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;

    private static readonly (string Key, string Label)[] _themes =
        [("light", "Light"), ("dark", "Dark"), ("system", "System")];

    private static readonly (string Key, string Label)[] _fontSizes =
        [("small", "Small"), ("medium", "Medium"), ("large", "Large")];

    private static readonly (string Key, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Español"),
        ("fr", "Français"),
        ("de", "Deutsch"),
        ("ja", "日本語"),
    ];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme} preview-font-{_fontSize}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private string GetLanguageLabel() =>
        _languages.FirstOrDefault(l => l.Key == _language).Label ?? _language;

    private async Task HandleSave()
    {
        _saving = true;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
        }
        finally
        {
            _saving = false;
        }
    }
}
