{"file_text": ".preview-area {
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

.preview-body {
    padding: 1rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    font-size: 0.8rem;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-theme-dark .preview-header,
.preview-theme-dark .preview-footer {
    border-color: #444;
}

.preview-theme-system {
    background: #f8f9fa;
    color: #212529;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

.preview-compact p {
    margin-bottom: 0.25rem;
}
