<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <div class="mb-2">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public UserProfile Profile { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task HandleSave()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges() => LoadFromProfile();
}

