@using sv_f673086dd3a348b99ff0f9c376186555.Services

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">
                <strong>Email Notifications</strong>
                <div class="text-muted small">Receive notifications via email</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">
                <strong>Push Notifications</strong>
                <div class="text-muted small">Receive push notifications in browser</div>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a weekly summary of activity</div>
            </label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    <div class="mb-4">
        @if (AvailableChannels.Count == 0)
        {
            <p class="text-muted">No channels available.</p>
        }
        else
        {
            @foreach (var channel in AvailableChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        }
    </div>

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs Prefs { get; set; } = default!;

    [Parameter]
    public List<string> AvailableChannels { get; set; } = ["general", "updates", "marketing", "alerts", "support"];

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        _saving = true;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await OnSave.InvokeAsync(updated);
        }
        finally
        {
            _saving = false;
        }
    }
}

