@using sv_f673086dd3a348b99ff0f9c376186555.Services

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <p class="text-muted small mb-0">
                    Add an extra layer of security to your account.
                </p>
            </div>
            <div class="d-flex align-items-center gap-2">
                <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox"
                           checked="@Settings.TwoFactorEnabled"
                           @onchange="HandleToggle2FA" />
                </div>
            </div>
        </div>
    </div>

    @if (Settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
        </p>
    }

    <ActiveSessionsTable Sessions="Settings.Sessions"
                         CurrentSessionId="@Settings.Sessions.FirstOrDefault()?.Id"
                         OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings Settings { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<bool> OnToggle2FA { get; set; }

    private async Task HandleToggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }
}

@using sv_f673086dd3a348b99ff0f9c376186555.Services

<div class="settings-section">
    <h4 class="mb-4">Appearance</h4>

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme.Key}")"
                               checked="@(_theme == theme.Key)"
                               @onchange="() => _theme = theme.Key" />
                        <label class="form-check-label" for="@($"theme-{theme.Key}")">@theme.Label</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size.Key}")"
                               checked="@(_fontSize == size.Key)"
                               @onchange="() => _fontSize = size.Key" />
                        <label class="form-check-label" for="@($"fs-{size.Key}")">@size.Label</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang.Key">@lang.Label</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">
                        <strong>Compact Mode</strong>
                        <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p>This is how your content will look with the selected settings.</p>
                    <button class="btn btn-sm btn-primary">Sample Button</button>
                    <span class="badge bg-info ms-2">Badge</span>
                </div>
                <div class="preview-footer text-muted">
                    Footer area · @GetLanguageLabel()
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings Settings { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "system";
    private string _fontSize = "medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;

    private static readonly (string Key, string Label)[] _themes =
        [("light", "Light"), ("dark", "Dark"), ("system", "System")];

    private static readonly (string Key, string Label)[] _fontSizes =
        [("small", "Small"), ("medium", "Medium"), ("large", "Large")];

    private static readonly (string Key, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Español"),
        ("fr", "Français"),
        ("de", "Deutsch"),
        ("ja", "日本語"),
    ];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme} preview-font-{_fontSize}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private string GetLanguageLabel() =>
        _languages.FirstOrDefault(l => l.Key == _language).Label ?? _language;

    private async Task HandleSave()
    {
        _saving = true;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
        }
        finally
        {
            _saving = false;
        }
    }
}

.preview-area {
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
}

.preview-body {
    padding: 1rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    font-size: 0.8rem;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-theme-dark .preview-header,
.preview-theme-dark .preview-footer {
    border-color: #444;
}

.preview-theme-system {
    background: #f8f9fa;
    color: #212529;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

.preview-compact p {
    margin-bottom: 0.25rem;
}

