@page "/settings"
@rendermode InteractiveServer
@using sv_f673086dd3a348b99ff0f9c376186555.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <main class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @if (_toast is not null)
            {
                <div class="alert @_toast.CssClass alert-dismissible fade show" role="alert">
                    @_toast.Message
                    <button type="button" class="btn-close" @onclick="DismissToast"></button>
                </div>
            }

            @switch (_activeSection)
            {
                case "profile":
                    <ProfileSection Profile="_profile!"
                                    OnSave="HandleSaveProfile" />
                    break;

                case "notifications":
                    <NotificationsSection Prefs="_notificationPrefs!"
                                          OnSave="HandleSaveNotifications" />
                    break;

                case "security":
                    <SecuritySection Settings="_securitySettings!"
                                     OnChangePassword="HandleChangePassword"
                                     OnRevokeSession="HandleRevokeSession"
                                     OnToggle2FA="HandleToggle2FA" />
                    break;

                case "appearance":
                    <AppearanceSection Settings="_appearanceSettings!"
                                       OnSave="HandleSaveAppearance" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string _activeSection = "profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    private ToastMessage? _toast;
    private CancellationTokenSource? _toastCts;

    private record ToastMessage(string Message, string CssClass);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            _profile = await profileTask;
            _notificationPrefs = await notifTask;
            _securitySettings = await securityTask;
            _appearanceSettings = await appearanceTask;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleSaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
        await ShowToast("Profile saved successfully.", "alert-success");
    }

    private async Task HandleSaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
        await ShowToast("Notification preferences saved.", "alert-success");
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password changed successfully.", "alert-success");
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Session revoked.", "alert-success");
    }

    private Task HandleToggle2FA(bool enabled)
    {
        // Re-create the settings record with the new 2FA state.
        // A real app would call a dedicated service method.
        _securitySettings = _securitySettings! with { TwoFactorEnabled = enabled };
        return ShowToast(
            enabled ? "Two-factor authentication enabled." : "Two-factor authentication disabled.",
            "alert-info");
    }

    private async Task HandleSaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
        await ShowToast("Appearance settings saved.", "alert-success");
    }

    private async Task ShowToast(string message, string cssClass)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toast = new ToastMessage(message, cssClass);
        StateHasChanged();

        try
        {
            await Task.Delay(4000, token);
            _toast = null;
        }
        catch (TaskCanceledException)
        {
            // New toast replaced this one
        }
    }

    private void DismissToast() => _toast = null;
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 60px);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.5rem;
    overflow: hidden;
    margin: 1rem;
    background: #fff;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section {
    max-width: 800px;
}

